import React, { useState } from 'react';
import { Outlet, useNavigate, useLocation, NavLink } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

const adminNavItems = [
  { to: '/admin/dashboard', icon: '📊', label: 'Dashboard' },
  { to: '/admin/students', icon: '👨‍🎓', label: 'Students' },
  { to: '/admin/routes', icon: '🗺️', label: 'Bus Routes' },
  { to: '/admin/fees', icon: '💰', label: 'Fee Management' },
];

const studentNavItems = [
  { to: '/student/dashboard', icon: '🏠', label: 'Dashboard' },
  { to: '/student/fees', icon: '💳', label: 'My Fees' },
];

export default function Layout() {
  const { user, logout, isAdmin } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [sidebarOpen, setSidebarOpen] = useState(false);

  const navItems = isAdmin ? adminNavItems : studentNavItems;
  const pageTitles = {
    '/admin/dashboard': { title: 'Dashboard', sub: 'Overview & Analytics' },
    '/admin/students': { title: 'Students', sub: 'Manage student records' },
    '/admin/routes': { title: 'Bus Routes', sub: 'Manage routes & fares' },
    '/admin/fees': { title: 'Fee Management', sub: 'Collect & track payments' },
    '/student/dashboard': { title: 'My Dashboard', sub: 'Your bus fee overview' },
    '/student/fees': { title: 'My Fees', sub: 'Fee history & receipts' },
  };

  const currentPage = pageTitles[location.pathname] || { title: 'Bus Fees', sub: '' };

  const handleLogout = () => { logout(); navigate('/login'); };

  return (
    <div className="layout">
      {sidebarOpen && <div style={{ position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.4)', zIndex: 99 }} onClick={() => setSidebarOpen(false)} />}
      <aside className={`sidebar ${sidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-logo">
          <span className="bus-icon">🚌</span>
          <div>
            <h1>Campus Bus</h1>
            <span>Fee Management</span>
          </div>
        </div>
        <nav className="sidebar-nav">
          <div className="nav-section">
            <div className="nav-section-label">{isAdmin ? 'Admin Menu' : 'Student Menu'}</div>
            {navItems.map(item => (
              <NavLink key={item.to} to={item.to} className={({ isActive }) => `nav-item ${isActive ? 'active' : ''}`} onClick={() => setSidebarOpen(false)}>
                <span className="icon">{item.icon}</span>
                {item.label}
              </NavLink>
            ))}
          </div>
        </nav>
        <div className="sidebar-footer">
          <div className="user-info">
            <div className="user-avatar">{user?.name?.charAt(0).toUpperCase()}</div>
            <div>
              <div className="user-name">{user?.name}</div>
              <div className="user-role">{user?.role}</div>
            </div>
          </div>
          <button className="logout-btn" onClick={handleLogout}>🚪 Sign Out</button>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <button style={{ display: 'none', background: 'none', border: 'none', fontSize: 22, cursor: 'pointer' }} onClick={() => setSidebarOpen(true)}>☰</button>
            <div className="topbar-title">
              <h2>{currentPage.title}</h2>
              <p>{currentPage.sub}</p>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
            <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>{new Date().toLocaleDateString('en-IN', { weekday: 'short', year: 'numeric', month: 'short', day: 'numeric' })}</span>
          </div>
        </header>
        <div className="page-content">
          <Outlet />
        </div>
      </main>
    </div>
  );
}
